mapper.select:
SELECT co.id, co.course_name, co.description, co.teacher_id, t.real_name as teacher_name, co.class_id, c.class_name, co.create_time, (SELECT COUNT(*) FROM student_course sc WHERE sc.course_id = co.id) as total_students, (SELECT COUNT(*) FROM training_report r WHERE r.course_id = co.id) as total_reports, (SELECT COUNT(*) FROM training_report r LEFT JOIN evaluation_record e ON r.id = e.report_id WHERE r.course_id = co.id AND e.id IS NOT NULL) as evaluated_reports, (SELECT AVG(e.total_score) FROM training_report r LEFT JOIN evaluation_record e ON r.id = e.report_id WHERE r.course_id = co.id AND e.total_score IS NOT NULL) as avg_score FROM course co LEFT JOIN sys_user t ON co.teacher_id = t.id LEFT JOIN sys_class c ON co.class_id = c.id
AND co.teacher_id = #{teacherId}
AND co.class_id = #{classId}
AND co.course_name LIKE CONCAT('%', #{courseName}, '%')
ORDER BY co.create_time DESC
